import React from 'react';
import '../styles/Dashboard.css';

const AVATAR_IMAGES = {
  base: {
    s1: '/Avatars/sittingavatar.jpg',
    s2: '/Avatars/skin-brown.png',
  },
  skinArmour: {
    s2_ar2: '/Avatars/skin-brown-iron.png',
    s2_ar3: '/Avatars/skin-brown-mage.png',
    s2_ar4: '/Avatars/skin-brown-gold.png',
    s2_ar5: '/Avatars/skin-brown-shadow.png',
    s2_ar6: '/Avatars/skin-brown-dragon.png',
  },
  armour: {
    ar1: null,
    ar2: '/Avatars/armour-iron.png',
    ar3: '/Avatars/purple-armour.png',
    ar4: '/Avatars/gold-armour.png',
    ar5: '/Avatars/armour-shadow.png',
    ar6: '/Avatars/red-armour.png',
  },
  pets: {
    p1: '/Avatars/pet-fire-dragon.png',
    p2: '/Avatars/pet-ice-dragon.png',
    p3: null,
    p4: '/Avatars/pet-golden-wyvern.png',
    p5: null,
    p6: null,
  },
};

const PET_INFO = {
  p1: { label: 'Fire Dragon',   emoji: '🐉', color: '#FF6B35' },
  p2: { label: 'Ice Dragon',    emoji: '🐲', color: '#74D7F7' },
  p3: { label: 'Shadow Drake',  emoji: '🦎', color: '#7E57C2' },
  p4: { label: 'Golden Wyvern', emoji: '🌟', color: '#FFD700' },
  p5: { label: 'Storm Drake',   emoji: '⚡', color: '#90CAF9' },
  p6: { label: 'Void Dragon',   emoji: '🌑', color: '#9C27B0' },
};

const getAvatarImage = (selections) => {
  if (!selections) return '/Avatars/sittingavatar.jpg';
  const skin   = selections.skin   || 's1';
  const armour = selections.armour || 'ar1';
  const skinArmourImg = AVATAR_IMAGES.skinArmour[skin + '_' + armour];
  if (skinArmourImg) return skinArmourImg;
  const armourImg = skin === 's1' ? AVATAR_IMAGES.armour[armour] : null;
  if (armourImg) return armourImg;
  return AVATAR_IMAGES.base[skin] || '/Avatars/sittingavatar.jpg';
};

const DashboardPet = ({ petId }) => {
  if (!petId) return null;
  const pet    = PET_INFO[petId];
  const petImg = AVATAR_IMAGES.pets[petId];
  if (petImg) {
    return (
      <div className="dashboard-pet">
        <img src={petImg} alt={pet?.label || 'Pet'} className="dashboard-pet-img"
          onError={(e) => { e.target.style.display = 'none'; }} />
        <span className="dashboard-pet-name">{pet?.label}</span>
      </div>
    );
  }
  return (
    <div className="dashboard-pet">
      <div className="dashboard-pet-emoji" style={{ background: (pet?.color || '#ccc') + '22', borderColor: pet?.color }}>
        <span>{pet?.emoji}</span>
      </div>
      <span className="dashboard-pet-name">{pet?.label}</span>
    </div>
  );
};

const Dashboard = ({ avatarSelections, avatarName }) => {
  const avatarImg = getAvatarImage(avatarSelections);
  const petId     = avatarSelections?.pets || null;

  return (
    <div className="page-container">
      <div className="dashboard-grid">

        <div className="card large-card">
          <div className="avatar-section">
            <div className="dashboard-avatar-scene">
              <div className="dashboard-avatar-wrap">
                <img src={avatarImg} alt={avatarName || 'My Avatar'}
                  className="dashboard-avatar-img"
                  onError={(e) => { e.target.src = '/Avatars/sittingavatar.jpg'; }} />
                {avatarName && <span className="dashboard-avatar-name">{avatarName}</span>}
              </div>
              <DashboardPet petId={petId} />
            </div>
            <div className="stat-bars">
              <div className="stat-bar" data-testid="hp-bar">
                <span className="stat-icon">❤️</span>
                <div className="progress-bar"><div className="progress-fill red" style={{ width: '65%' }}></div></div>
                <span className="stat-label">HP</span>
              </div>
              <div className="stat-bar" data-testid="energy-bar">
                <span className="stat-icon">⚡</span>
                <div className="progress-bar"><div className="progress-fill blue" style={{ width: '80%' }}></div></div>
                <span className="stat-label">Energy</span>
              </div>
              <div className="stat-bar" data-testid="discipline-bar">
                <span className="stat-icon">💪</span>
                <div className="progress-bar"><div className="progress-fill green" style={{ width: '45%' }}></div></div>
                <span className="stat-label">Discipline</span>
              </div>
            </div>
          </div>
        </div>

        <div className="card small-card" data-testid="heart-rate-card"><h3>Heart Rate</h3><div className="heart-icon">❤️</div></div>
        <div className="card small-card" data-testid="sleep-card"><h3>Sleep</h3></div>
        <div className="card small-card" data-testid="steps-card"><h3>Steps</h3></div>
        <div className="card small-card" data-testid="calories-card"><h3>Calories</h3></div>
        <div className="card medium-card" data-testid="challenges-summary-card"><h3>Challenges</h3></div>
        <div className="card medium-card" data-testid="stress-card"><h3>Stress</h3></div>
        <button className="dashboard-action-btn log-btn" data-testid="log-activities-btn">Log Activities and Food Intake</button>
        <button className="dashboard-action-btn sync-btn" data-testid="sync-device-btn">Sync Device</button>
      </div>
    </div>
  );
};

export default Dashboard;
